[تحذير]
خد بالك: الـ Arrays بتبدأ من صفر (Zero-Based)

العنصر & الـ Index \\
العنصر الأول & `0` \\
العنصر التاني & `1` \\
العنصر التالت & `2` \\
\end{tabular}
\end{center}

يعني الترقيم بيبدأ من صفر مش من واحد!
\end{warningbox}

example.javascript:
const friends = ["Michael", "Steven", "Peter"];
//                   0          1         2     <-- index

// First element (index = 0)
console.log(friends[0]);
// Output: "Michael"

// Third element (index = 2)
console.log(friends[2]);
// Output: "Peter"

const friends = ["Michael", "Steven", "Peter"];

// Number of elements in the array
console.log(friends.length);
// Output: 3

const friends = ["Michael", "Steven", "Peter"];

// Get the last element automatically:
console.log(friends[friends.length - 1]);
// Output: "Peter"

// Under the hood:
// friends.length = 3
// 3 - 1 = 2
// friends[2] = "Peter"

const friends = ["Michael", "Steven", "Peter"];

// Change element with index 2 (Peter) to Jay
friends[2] = "Jay";

console.log(friends);
// Output: ["Michael", "Steven", "Jay"]

const friends = ["Michael", "Steven", "Peter"];

// This works - change an element inside the array
friends[2] = "Jay";

// This does NOT work - replace the whole array
// friends = ["Bob", "Alice"];
// Error: Assignment to constant variable

const firstName = "Jonas";
const friends = ["Michael", "Steven", "Peter"];

// Example of an array that contains different data types
const jonas = [
  firstName,        // first name
  "Schmedtmann",    // last name
  2037 - 1991,      // age (result of expression)
  "teacher",        // job
  friends           // friends array
];

console.log(jonas);
// Output: ["Jonas", "Schmedtmann", 46, "teacher", Array(3)]

